import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter, InMemoryWebhookTransport } from '../../src/adapters/webhook.adapter.js';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';

/**
 * Integration tests for the full notification pipeline.
 *
 * Wires up: EventBus → NotificationService → Adapters (email/SMS/webhook)
 *           + PreferencesService (preference checks)
 *           + NotificationHistoryService (delivery logging)
 *
 * Tests end-to-end flows, not individual components.
 */
describe('Notification Pipeline Integration', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let db: Database;

  // Transports (in-memory, inspectable)
  let emailTransport: InMemoryTransport;
  let smsTransport: InMemorySmsTransport;
  let webhookTransport: InMemoryWebhookTransport;

  // Services
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;

  // Shared test data
  const alice = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
  };

  const bob = {
    id: 'user-2',
    name: 'Bob',
    email: 'bob@example.com',
    role: 'member' as const,
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
  };

  const sampleOrder = {
    id: 'order-1',
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
    ],
    total: 45,
    status: 'pending' as const,
    createdAt: new Date('2025-06-01'),
    updatedAt: new Date('2025-06-01'),
  };

  beforeEach(() => {
    resetNotificationIdCounter();
    resetLogIdCounter();

    db = new Database();
    eventBus = new EventBus();

    // Build adapters with in-memory transports
    emailTransport = new InMemoryTransport();
    const emailAdapter = new EmailAdapter({
      transport: emailTransport,
      recipientResolver: async (recipient) => {
        const emails: Record<string, string> = {
          'user-1': 'alice@example.com',
          'user-2': 'bob@example.com',
        };
        if (recipient.includes('@')) return recipient;
        return emails[recipient] ?? null;
      },
    });

    smsTransport = new InMemorySmsTransport();
    const smsAdapter = new SmsAdapter({
      transport: smsTransport,
      phoneNumberResolver: async (recipient) => {
        const phones: Record<string, string> = {
          'user-1': '+15551234567',
          'user-2': '+15559876543',
        };
        return phones[recipient] ?? null;
      },
    });

    webhookTransport = new InMemoryWebhookTransport();
    const webhookAdapter = new WebhookAdapter({
      transport: webhookTransport,
      urlResolver: async (recipient) => {
        const urls: Record<string, string> = {
          'user-1': 'https://hooks.example.com/user-1',
          'user-2': 'https://hooks.example.com/user-2',
        };
        if (recipient.startsWith('http')) return recipient;
        return urls[recipient] ?? null;
      },
    });

    // Wire up the notification service
    service = new NotificationService(eventBus);
    service.registerAdapter(emailAdapter);
    service.registerAdapter(smsAdapter);
    service.registerAdapter(webhookAdapter);

    // Set up preferences
    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    service.setPreferencesService(preferencesService);

    // Set up history
    const logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    service.setHistoryService(historyService);
  });

  // ── Email Channel ──────────────────────────────────────────────────

  describe('email channel end-to-end', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email delivered
      const emails = emailTransport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.to).toBe('alice@example.com');
      expect(emails[0]!.subject).toContain('Order Confirmation');
      expect(emails[0]!.text).toContain('Widget x2');
      expect(emails[0]!.text).toContain('Gadget x1');
      expect(emails[0]!.text).toContain('$45.00');

      // History recorded
      const logs = historyService.getByUserId(alice.id);
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.type).toBe('order-confirmation');
    });

    it('should deliver welcome email on user:created event', async () => {
      // Default prefs — email enabled by default
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: alice,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = emailTransport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.subject).toContain('Welcome');
      expect(emails[0]!.subject).toContain('Alice');
      expect(emails[0]!.text).toContain('account has been created');
    });

    it('should deliver order status update email on order:status-changed', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...sampleOrder, status: 'shipped' },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = emailTransport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.subject).toContain('Order Update');
      expect(emails[0]!.text).toContain('confirmed');
      expect(emails[0]!.text).toContain('shipped');
    });
  });

  // ── SMS Channel ────────────────────────────────────────────────────

  describe('SMS channel end-to-end', () => {
    it('should deliver SMS when user has opted in to SMS', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        sms: { enabled: true },
      });

      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
      });

      const messages = smsTransport.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+15551234567');
      expect(messages[0]!.body).toContain('Order Confirmation');

      // History recorded
      const logs = historyService.getByChannel('sms');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('sent');
    });

    it('should suppress SMS when user has not opted in', async () => {
      // No preferences → SMS defaults to disabled
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(smsTransport.getSentMessages()).toHaveLength(0);

      // Suppressed notification recorded in history
      const logs = historyService.getByChannel('sms');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('suppressed');
    });
  });

  // ── Webhook Channel ────────────────────────────────────────────────

  describe('webhook channel end-to-end', () => {
    it('should deliver webhook notification when user has opted in', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        webhook: { enabled: true },
      });

      await service['sendNotification']({
        type: 'order-status-update',
        channel: 'webhook',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Update: order-1',
        body: 'Your order status has changed to shipped.',
      });

      const deliveries = webhookTransport.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]!.url).toBe('https://hooks.example.com/user-1');
      expect(deliveries[0]!.body.type).toBe('order-status-update');
      expect(deliveries[0]!.body.subject).toBe('Order Update: order-1');

      // History recorded
      const logs = historyService.getByChannel('webhook');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('sent');
    });

    it('should suppress webhook when user has not opted in', async () => {
      // No preferences → webhook defaults to disabled
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(webhookTransport.getDeliveries()).toHaveLength(0);

      const logs = historyService.getByChannel('webhook');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('suppressed');
    });
  });

  // ── History Logging ────────────────────────────────────────────────

  describe('notification history', () => {
    it('should log all delivered notifications in history', async () => {
      // Enable all channels
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      // Send via email (via event)
      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      // Send via SMS
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      // Send via webhook
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      const allLogs = historyService.getAll();
      expect(allLogs).toHaveLength(3);

      const channels = allLogs.map((l) => l.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);

      // All should be 'sent'
      expect(allLogs.every((l) => l.status === 'sent')).toBe(true);
    });

    it('should log suppressed notifications separately from sent ones', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true },
        sms: { enabled: false },
      });

      // Email goes through
      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      // SMS is suppressed
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      const allLogs = historyService.getAll();
      expect(allLogs).toHaveLength(2);

      const sentLogs = historyService.query({ status: 'sent' });
      expect(sentLogs).toHaveLength(1);
      expect(sentLogs[0]!.channel).toBe('email');

      const suppressedLogs = historyService.query({ status: 'suppressed' });
      expect(suppressedLogs).toHaveLength(1);
      expect(suppressedLogs[0]!.channel).toBe('sms');
    });

    it('should associate history entries with the correct user', async () => {
      // Send notifications for two different users
      await eventBus.emit({
        type: 'user:created',
        user: alice,
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: bob,
        timestamp: new Date(),
      } as UserCreatedEvent);

      const aliceLogs = historyService.getByUserId(alice.id);
      const bobLogs = historyService.getByUserId(bob.id);

      expect(aliceLogs).toHaveLength(1);
      expect(bobLogs).toHaveLength(1);
      expect(aliceLogs[0]!.type).toBe('welcome');
      expect(bobLogs[0]!.type).toBe('welcome');
    });
  });

  // ── Preference Enforcement ─────────────────────────────────────────

  describe('preference enforcement', () => {
    it('should not send on any channel when user disables email', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: false },
      });

      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(0);
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should respect category-based preferences', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: {
          enabled: true,
          subscribedCategories: ['account'], // not subscribed to 'order-updates'
        },
      });

      // Order notification should be suppressed (order-updates category)
      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(0);

      // Welcome notification should go through (account category)
      await eventBus.emit({
        type: 'user:created',
        user: alice,
        timestamp: new Date(),
      } as UserCreatedEvent);

      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(emailTransport.getSentEmails()[0]!.subject).toContain('Welcome');
    });

    it('should enforce channel independence — enable email, disable SMS and webhook', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      // Email works
      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);
      expect(emailTransport.getSentEmails()).toHaveLength(1);

      // SMS suppressed
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Test',
      });
      expect(smsTransport.getSentMessages()).toHaveLength(0);

      // Webhook suppressed
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Test',
      });
      expect(webhookTransport.getDeliveries()).toHaveLength(0);

      // History shows 1 sent, 2 suppressed
      const sent = historyService.query({ status: 'sent' });
      const suppressed = historyService.query({ status: 'suppressed' });
      expect(sent).toHaveLength(1);
      expect(suppressed).toHaveLength(2);
    });

    it('should send on all channels when all are enabled for the notification category', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      // Email via event
      await eventBus.emit({
        type: 'order:created',
        order: sampleOrder,
        user: alice,
        timestamp: new Date(),
      } as OrderCreatedEvent);

      // SMS directly
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      // Webhook directly
      await service['sendNotification']({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: alice.id,
        userId: alice.id,
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      });

      expect(emailTransport.getSentEmails()).toHaveLength(1);
      expect(smsTransport.getSentMessages()).toHaveLength(1);
      expect(webhookTransport.getDeliveries()).toHaveLength(1);
    });

    it('should suppress email when frequency is set to none', async () => {
      preferencesService.createPreferences({
        userId: alice.id,
        email: { enabled: true, frequency: 'none' },
